const MAPS: Partial<Record<LocaleCode, Map>> = { ur: UR, ar: AR };

export function L(locale: LocaleCode, text: string): string {
  if (!text || locale === "en") return text;
  return MAPS[locale]?.[text] ?? text;
}

// Recursively translate every string in a value (object/array/string).
export function deepLocalize<T>(locale: LocaleCode, value: T): T {
  if (locale === "en" || value == null) return value;
  if (typeof value === "string") return L(locale, value) as unknown as T;
  if (Array.isArray(value)) return value.map((v) => deepLocalize(locale, v)) as unknown as T;
  if (typeof value === "object") {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) out[k] = deepLocalize(locale, v);
    return out as T;
  }
  return value;
}
